import BcomComponent from "../common/component";
const app = getApp();
BcomComponent({
    props: {
        title: {
            type: String,
            value: ""
        },
        boardColor: { //画板颜色
            type: String,
            value: "#ffffff",
            observer(val) {
                this.set({
                    _boardColor: val
                });
            }
        },
        backgroundColor: { //背景颜色
            type: String,
            value: "#ffa500",
            observer(val) {
                this.set({
                    _backgroundColor: val
                });
            }
        },
        size: {
            type: Number,
            value: 8,
            observer(val) {
                this.set({
                    _size: val
                });
            }
        },
        color: {
            type: String,
            value: "#1A1A1A",
            observer(val) {
                this.set({
                    _color: val
                });
            }
        },
        fileType: { //生成图片类型；仅支持png、jpg两种
            type: String,
            value: "png"
        },
        quality: { //生成图片的质量，目前仅对 jpg 有效。取值范围为 (0, 1]，不在范围内时当作 1.0 处理。
            type: Number,
            value: 1
        },
        buttonList: {
            type: Array,
            value: ["cancel", "setting", "reset", "preview", "save", "confirm"]
        }
    },
    /**
     * 页面的初始数据
     */
    data: {
        _boardColor: "", //画板颜色
        _backgroundColor: "", //背景色
        _color: '', // 颜色
        _size: 0, // 笔记倍数
        isShowSetting: false, //设置弹窗显示
        defaultData: {}
    },
    mounted() {
        const {
            boardColor,
            backgroundColor,
            color,
            size
        } = this.data;
        this.set({
            _boardColor: boardColor,
            _backgroundColor: backgroundColor,
            _color: color,
            _size: size,
        });
        this.isSign = false;
        wx.createSelectorQuery().in(this)
            .select('#handWriting')
            .fields({
                node: true,
                size: true
            })
            .exec(res => {
                this.canvas = res[0].node;
                this.ctx = this.canvas.getContext('2d');
                this.systemInfo = wx.getSystemInfoSync();
                const dpr = this.systemInfo.pixelRatio;
                this.canvas.width = res[0].width * dpr;
                this.canvas.height = res[0].height * dpr;
                this.ctx.scale(dpr, dpr);
                this.setCanvasBg(this.data._boardColor);
                this.ctx.strokeStyle = this.data._color;
                this.ctx.lineWidth = this.data._size;
                this.ctx.lineCap = "round";
                this.ctx.lineJoin = "round";
            });
    },

    methods: {
        
        // 笔迹开始
        uploadScaleStart(e) {
            // debugger
            if (e.type != 'touchstart') return false;
            this.ctx.beginPath();
            this.ctx.moveTo(e.touches[0].x, e.touches[0].y);
        },
        // 笔迹移动
        uploadScaleMove(e) {
            if (e.type != 'touchmove') return false;
            if (e.cancelable) {
                // 判断默认行为是否已经被禁用
                if (!e.defaultPrevented) {
                    e.preventDefault();
                }
            }
            this.ctx.lineTo(e.touches[0].x, e.touches[0].y);
            this.ctx.stroke();
            this.isSign = true;
        },
        // 笔迹结束
        uploadScaleEnd(e) {
            // debugger
            // this.ctx.closePath();
        },
        // 重写
        retDraw() {
            if (this.hasClick()) {
                wx.showToast({
                    title: '点击太频繁了',
                    icon: 'none'
                });
                return;
            }
            this.setCanvasBg(this.data._boardColor);
        },
        /**
         * 保存
         */
        subCanvas() {
            if (this.hasClick()) {
                wx.showToast({
                    title: '点击太频繁了',
                    icon: 'none'
                });
                return;
            }
            if (!this.isSign) {
                wx.showToast({
                    title: '您未签字',
                    icon: "none"
                });
                return;
            }
            wx.canvasToTempFilePath({
                x: 0,
                y: 0,
                width: this.canvas.width,
                height: this.canvas.height,
                destWidth: this.canvas.width * this.systemInfo.pixelRatio,
                destHeight: this.canvas.height * this.systemInfo.pixelRatio,
                canvas: this.canvas,
                fileType: this.data.fileType,
                quality: this.data.quality,
                success(res) {
                    wx.saveImageToPhotosAlbum({
                        filePath: res.tempFilePath,
                        success(res) {
                            wx.showToast({
                                title: '已保存到相册',
                                duration: 2000
                            });
                        }
                    });
                }
            });
        },
        /**
         * 取消
         */
        cancelTap() {
            if (this.hasClick()) {
                wx.showToast({
                    title: '点击太频繁了',
                    icon: 'none'
                });
                return;
            }
            this.$emit("cancel");
        },
        /**
         * 确定
         */
        confirmTap() {
            if (this.hasClick()) {
                wx.showToast({
                    title: '点击太频繁了',
                    icon: 'none'
                });
                return;
            }
            if (!this.isSign) {
                wx.showToast({
                    title: '您未签字',
                    icon: "none"
                });
                return;
            }
            wx.canvasToTempFilePath({
                x: 0,
                y: 0,
                width: this.canvas.width,
                height: this.canvas.height,
                destWidth: this.canvas.width * this.systemInfo.pixelRatio,
                destHeight: this.canvas.height * this.systemInfo.pixelRatio,
                canvas: this.canvas,
                fileType: this.data.fileType,
                quality: this.data.quality,
                success: res => {
                    this.$emit("confirm", {
                        path: res.tempFilePath,
                        width: this.canvas.width,
                        height: this.canvas.height
                    });
                }
            });
        },
        //预览
        previewCanvasImg() {
            if (this.hasClick()) {
                wx.showToast({
                    title: '点击太频繁了',
                    icon: 'none'
                });
                return;
            }
            if (!this.isSign) {
                wx.showToast({
                    title: '您未签字',
                    icon: "none"
                })
                return;
            }
            wx.canvasToTempFilePath({
                x: 0,
                y: 0,
                width: this.canvas.width,
                height: this.canvas.height,
                destWidth: this.canvas.width * 2,
                destHeight: this.canvas.height * 2,
                canvas: this.canvas,
                fileType: "jpg",
                quality: 1,
                success(res) {
                    wx.previewImage({
                        urls: [res.tempFilePath], //预览图片 数组
                    })
                }
            })
        },
        // 设置线条粗细
        setLineSize(_size) {
            this.ctx.lineWidth = _size;
        },
        //设置线条颜色
        setLineColor(color) {
            this.ctx.strokeStyle = color;
        },
        //设置画板背景并重写
        setCanvasBg(color = "#ffffff") {
            this.isSign = false;
            this.ctx.fillStyle = color;
            this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
            this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
        },
        //设置显示
        settingShow() {
            const {
                _backgroundColor,
                _color,
                _size,
                _boardColor
            } = this.data;

            this.set({
                defaultData: {
                    backgroundColor: _backgroundColor,
                    color: _color,
                    size: _size,
                    boardColor: _boardColor
                },
                isShowSetting: true
            });
        },
        //取消设置
        settingCancel() {
            this.set({
                isShowSetting: false
            });
        },
        //确定设置
        settingConfirm(e) {
            const data = e.detail;
            const {
                _color,
                _size,
                _boardColor
            } = this.data;
            if(data.color != _color) {
                this.setLineColor(data.color);
            }
            if(data.size != _size) {
                this.setLineSize(data.size);
            }
            if(data.boardColor != _boardColor) {
                this.setCanvasBg(data.boardColor);
            }
            this.set({
                _backgroundColor: data.backgroundColor,
                _color: data.color,
                _size: data.size,
                _boardColor: data.boardColor,
                isShowSetting: false
            });
        }
    }

})